$(document).ready(function(){$(window).scroll(function(){$(window).scrollTop()>=10?$(".navbar").addClass("navbar--animated"):$(".navbar").removeClass("navbar--animated")}),$("[data-click=scroll-to-target]").on("click",function(a){a.preventDefault(),a.stopPropagation();var o=$(this).attr("href");if($(window).width()<991)var t=79;else t=97;$("html, body").animate({scrollTop:$(o).offset().top-t},500),$(".navbar-collapse").removeClass("show")})});